package com.samudhra.certificates.controller;
import com.samudhra.certificates.dto.ApiResponse; import com.samudhra.certificates.service.*; import org.springframework.web.bind.annotation.*; import org.springframework.web.multipart.MultipartFile;
@RestController @RequestMapping("/api/upload") public class UploadController {private final StorageService storage;private final CurrentUserService current;public UploadController(StorageService s,CurrentUserService c){storage=s;current=c;} @PostMapping("/{purpose:logo|seal|signature|background}") public ApiResponse<?> upload(@PathVariable String purpose,@RequestParam MultipartFile file)throws Exception{var upload=storage.store(file,purpose,current.user());return ApiResponse.ok(java.util.Map.of("id",upload.getId(),"url",upload.getUrl(),"purpose",purpose));}}
